// ─── NODE 1: PARSE, FILTER, CHECK DUPLICATE — ALL IN ONE ───────
// Handles all filtering + corrections table duplicate check
// Keeps all fields on the item — no broken pairing

const item = $input.item.json;

// ── Extract fields
const emailId     = item.id || '';
const threadId    = item.threadId || '';
const messageId   = item.messageId || '';
const labelIds    = item.labelIds || [];
const date        = item.date || new Date().toISOString();

const fromAddress = (item.from?.value?.[0]?.address || '').toLowerCase().trim();
const fromName    = (item.from?.value?.[0]?.name || '').trim();
const replyTo     = (item.replyTo?.value?.[0]?.address || fromAddress).toLowerCase().trim();
const toAddress   = (item.to?.value?.[0]?.address || '').toLowerCase().trim();
const subject     = (item.subject || '(No Subject)').trim();

const rawText = item.text || item.snippet || '';
const body = rawText
  .replace(/https?:\/\/\S+/g, '')
  .replace(/\[.*?\]/g, '')
  .replace(/\r\n/g, '\n')
  .replace(/\n{3,}/g, '\n\n')
  .replace(/[ \t]+/g, ' ')
  .trim();

const headers   = item.headers || {};
const listUnsub = headers['list-unsubscribe'] || '';

// ── Filter: decide if this is a real customer email
let isCustomerEmail = true;
let skipReason = '';

if (!threadId) {
  isCustomerEmail = false;
  skipReason = 'NO_THREAD_ID';
}

if (isCustomerEmail && (!body || body.length < 20)) {
  isCustomerEmail = false;
  skipReason = 'EMPTY_BODY';
}

const marketingSignals = [
  listUnsub !== '',
  labelIds.includes('CATEGORY_PROMOTIONS'),
  labelIds.includes('CATEGORY_UPDATES'),
  labelIds.includes('CATEGORY_FORUMS'),
  /unsubscribe|opt.out|mailing.list/i.test(body),
  /no.reply|noreply|donotreply/i.test(fromAddress),
];
const marketingScore = marketingSignals.filter(Boolean).length;
const hasNoreply = /no.?reply|noreply|donotreply/i.test(fromAddress);
if (isCustomerEmail && (marketingScore >= 2 || hasNoreply)) {
  isCustomerEmail = false;
  skipReason = 'MARKETING_EMAIL';
}

if (isCustomerEmail && labelIds.includes('SPAM')) {
  isCustomerEmail = false;
  skipReason = 'SPAM';
}

const bouncePatterns = [
  /delivery (status notification|failed|failure)/i,
  /message not delivered|undeliverable/i,
  /mail delivery (failed|subsystem)/i,
  /bounce|mailer.daemon/i,
];
if (isCustomerEmail && bouncePatterns.some(p => p.test(subject) || p.test(fromAddress))) {
  isCustomerEmail = false;
  skipReason = 'BOUNCE';
}

const internalDomains = ['incredmoney.com', 'incred.com'];
const senderDomain = (fromAddress.split('@')[1] || '');
if (isCustomerEmail && internalDomains.some(d => senderDomain.includes(d))) {
  isCustomerEmail = false;
  skipReason = 'INTERNAL_EMAIL';
}

// Skip emails that are in SENT folder — these are support replies not customer emails
if (isCustomerEmail && labelIds.includes('SENT')) {
  isCustomerEmail = false;
  skipReason = 'SENT_ITEM_NOT_CUSTOMER';
}

// Add this after the internalDomains check
const automatedSenders = [
  'digio.in',
  'nsdl.co.in', 
  'cdslindia.com',
  'karvy.com',
  'kfintech.com',
  'bseindia.com',
  'nseindia.com',
  'alerts.razorpay.com',
  'hdfcbank.com',
  'icicibank.com',
  'axisbank.com',
  'paytm.com',
  'phonepe.com',
];
if (isCustomerEmail && automatedSenders.some(d => senderDomain.includes(d))) {
  isCustomerEmail = false;
  skipReason = 'AUTOMATED_SERVICE_EMAIL';
}

const automatedSubjectPatterns = [
  /document signed/i,
  /signed successfully/i,
  /esign|e-sign/i,
  /otp for|your otp/i,
  /transaction alert|transaction notification/i,
  /payment (received|successful|failed|declined)/i,
  /debit alert|credit alert/i,
  /account (statement|summary)/i,
  /kyc (verification|completed|approved|rejected)/i,
  /welcome to|account (created|activated)/i,
];
if (isCustomerEmail && automatedSubjectPatterns.some(p => p.test(subject))) {
  isCustomerEmail = false;
  skipReason = 'AUTOMATED_SUBJECT';
}

// ── Return with all fields intact
return {
  json: {
    emailId,
    threadId,
    messageId,
    fromAddress,
    fromName,
    replyTo,
    toAddress,
    subject,
    body,
    date,
    labelIds,
    isCustomerEmail,
    skipReason,
    marketingScore,
    bodyLength: body.length,
  }
};

