// ─── NODE 3: MERGE DUPLICATE CHECK RESULT WITH EMAIL FIELDS ────
// $input.item.json = result from Postgres (has already_processed)
// $('Is Customer Email').item.json = full email fields
// Using IF node reference because IF nodes preserve pairing correctly

const dbResult    = $input.item.json;
const emailFields = $('Is Customer Email').item.json;

return {
  json: {
    ...emailFields,
    alreadyProcessed: dbResult.already_processed === true || dbResult.already_processed === 'true',
  }
};

// ─── ASSEMBLE THREAD ────────────────────────────────────────────
const originalEmail = $input.item.json;

const cleanBody = (originalEmail.body || '')
  .replace(/https?:\/\/\S+/g, '')
  .replace(/\r\n/g, '\n')
  .replace(/\n{3,}/g, '\n\n')
  .replace(/[ \t]+/g, ' ')
  .trim();

const conversationText = 'CUSTOMER (' + originalEmail.date + '):\n' + cleanBody;

return {
  json: {
    threadId:            originalEmail.threadId,
    subject:             originalEmail.subject,
    fromAddress:         originalEmail.fromAddress,
    date:                originalEmail.date,
    primaryCustomerBody: cleanBody,
    latestSupportReply:  '',
    conversationText,
    hasSupportReply:     true,
    totalMessages:       1,
    customerMsgCount:    1,
    supportReplyCount:   0,
  }
};

// ─── PARSE KB ENTRIES ────────────────────────────────────────────
const item   = $input.item.json;
const thread = $('Assemble Thread').item.json;

const rawOutput = (item.output || '')
  .replace(/```json/gi, '')
  .replace(/```/g, '')
  .trim();

let parsed = { kb_entries: [], scenario_patterns: [] };
try {
  parsed = JSON.parse(rawOutput);
  if (!parsed.kb_entries) parsed.kb_entries = [];
  if (!parsed.scenario_patterns) parsed.scenario_patterns = [];
} catch(e) {
  parsed = { kb_entries: [], scenario_patterns: [] };
}

// Filter by confidence
const kbEntries = (parsed.kb_entries || []).filter(e => (e.confidence || 0) >= 0.7);
const scenarios = (parsed.scenario_patterns || []).filter(e => (e.confidence || 0) >= 0.7);

const hasAnything = kbEntries.length > 0 || scenarios.length > 0;

if (!hasAnything) {
  return {
    json: {
      hasEntries:          false,
      threadId:            thread.threadId,
      subject:             thread.subject,
      fromAddress:         thread.fromAddress,
      date:                thread.date,
      primaryCustomerBody: thread.primaryCustomerBody,
      latestSupportReply:  thread.latestSupportReply,
    }
  };
}

// Take best KB entry by confidence
const bestKB = kbEntries.length > 0
  ? kbEntries.sort((a, b) => (b.confidence || 0) - (a.confidence || 0))[0]
  : null;

// Take best scenario pattern by confidence
const bestScenario = scenarios.length > 0
  ? scenarios.sort((a, b) => (b.confidence || 0) - (a.confidence || 0))[0]
  : null;

return {
  json: {
    hasEntries:           true,
    threadId:             thread.threadId,
    subject:              thread.subject,
    fromAddress:          thread.fromAddress,
    date:                 thread.date,
    primaryCustomerBody:  thread.primaryCustomerBody,
    latestSupportReply:   thread.latestSupportReply,

    // KB entry fields
    hasKB:                !!bestKB,
    question:             bestKB ? (bestKB.question || '').trim() : '',
    answer:               bestKB ? (bestKB.answer || '').trim() : '',
    category:             bestKB ? (bestKB.category || 'general_inquiry') : '',
    kbConfidence:         bestKB ? (bestKB.confidence || 0) : 0,

    // Scenario pattern fields
    hasScenario:          !!bestScenario,
    patternName:          bestScenario ? (bestScenario.pattern_name || '').trim() : '',
    triggerKeywords:      bestScenario ? (bestScenario.trigger_keywords || []) : [],
    scenarioCategory:     bestScenario ? (bestScenario.category || 'general_inquiry') : '',
    situation:            bestScenario ? (bestScenario.situation || '').trim() : '',
    responseApproach:     bestScenario ? (bestScenario.response_approach || '').trim() : '',
    dataToCheck:          bestScenario ? (bestScenario.data_to_check || '').trim() : '',
    exampleResponse:      bestScenario ? (bestScenario.example_response || '').trim() : '',
    scenarioConfidence:   bestScenario ? (bestScenario.confidence || 0) : 0,
  }
};

