// Merge duplicate check result with KB entry fields
// Reference Has KB Entries IF node — IF nodes preserve pairing reliably
const dbResult = $input.item.json;
const kbEntry  = $('Has KB Entries').item.json;

const alreadyExists =
  dbResult.already_exists === true ||
  dbResult.already_exists === 'true' ||
  dbResult.already_exists === 't' ||
  String(dbResult.already_exists).toLowerCase() === 'true';

return {
  json: {
    ...kbEntry,
    alreadyExists,
  }
};

const item = $input.item.json;

const OPENAI_API_KEY = 'YOUR_OPENAI_API_KEY';

// ── Helper: generate embedding ────────────────────────────────
async function getEmbedding(text) {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.openai.com/v1/embeddings',
    headers: {
      'Authorization': `Bearer ${OPENAI_API_KEY}`,
      'Content-Type': 'application/json',
    },
    body: {
      model: 'text-embedding-3-small',
      input: text || '',
    },
    json: true,
  });
  return '[' + response.data[0].embedding.join(',') + ']';
}

// ── Generate embeddings ───────────────────────────────────────
const kbEmbedding         = await getEmbedding(item.question + ' ' + item.answer);
const scenarioEmbedding   = await getEmbedding((item.situation || '') + ' ' + (item.responseApproach || ''));
const correctionEmbedding = await getEmbedding(item.primaryCustomerBody || '');

// ── Connect to Postgres ───────────────────────────────────────
const { Client } = require('pg');
const client = new Client({
  host:     'YOUR_POSTGRES_HOST',
  port:     5432,
  database: 'YOUR_DATABASE_NAME',
  user:     'YOUR_POSTGRES_USER',
  password: 'YOUR_POSTGRES_PASSWORD',
  ssl:      false,
});

await client.connect();

try {
  // Insert KB entry
  await client.query(`
    INSERT INTO kb_data (question, answer, embedding, updated_by, created_at, updated_at)
    VALUES ($1, $2, $3::vector, 'historical_import', NOW(), NOW())
    ON CONFLICT ON CONSTRAINT kb_data_question_unique 
    DO UPDATE SET updated_at = NOW()
  `, [item.question, item.answer, kbEmbedding]);

  // Insert Scenario Pattern
  if (item.hasScenario && item.patternName) {
    await client.query(`
      INSERT INTO scenario_patterns (
        pattern_name, category, situation, response_approach,
        data_to_check, example_response, source_thread_id,
        confidence, embedding, created_at, updated_at
      ) VALUES ($1, $2, $3, $4, $5, $6, $7, $8, $9::vector, NOW(), NOW())
      ON CONFLICT ON CONSTRAINT scenario_patterns_name_unique
      DO UPDATE SET updated_at = NOW()
    `, [
      item.patternName,
      item.scenarioCategory || 'general_inquiry',
      item.situation || '',
      item.responseApproach || '',
      item.dataToCheck || '',
      item.exampleResponse || '',
      item.threadId,
      item.scenarioConfidence || 0,
      scenarioEmbedding,
    ]);
  }

  // Insert Correction
  await client.query(`
    INSERT INTO corrections (
      gmail_thread_id, original_email_body, human_sent_text,
      classification, diff_summary, embedding, source, created_at
    ) VALUES ($1, $2, $3, $4, $5, $6::vector, 'historical_import', NOW())
  `, [
    item.threadId,
    item.primaryCustomerBody || '',
    item.latestSupportReply || '',
    item.category || 'general_inquiry',
    'Historical import: ' + (item.subject || ''),
    correctionEmbedding,
  ]);

  // Log to email_logs
  await client.query(`
    INSERT INTO email_logs (
      gmail_thread_id, sender_email, subject,
      classification, status, notes, processed_at
    ) VALUES ($1, $2, $3, $4, 'kb_extracted', $5, NOW())
    ON CONFLICT DO NOTHING
  `, [
    item.threadId,
    item.fromAddress || '',
    item.subject || '',
    item.category || 'general_inquiry',
    'KB inserted | confidence: ' + (item.kbConfidence || 0),
  ]);

} finally {
  await client.end();
}

return {
  json: {
    threadId:    item.threadId,
    subject:     item.subject,
    question:    item.question,
    hasScenario: item.hasScenario,
    status:      'inserted',
  }
};
